SELECT COALESCE(SUM(good_qty), 0)
FROM production_result
WHERE order_id = #{orderId}

SELECT r.*, p.product_name, w.target_qty FROM production_result r JOIN work_order w ON r.order_id = w.order_id JOIN product p ON w.product_id = p.product_id
AND p.product_name LIKE CONCAT('%', #{productName}, '%')
AND r.defect_type = #{defectType}
AND r.worker LIKE CONCAT('%', #{worker}, '%')
AND r.result_date >= #{startDate}
AND r.result_date <= #{endDate}
ORDER BY r.created_at DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*)
FROM production_result r
JOIN work_order w ON r.order_id = w.order_id
JOIN product p ON w.product_id = p.product_id


        AND p.product_name LIKE CONCAT('%', #{productName}, '%')


        AND r.defect_type = #{defectType}


        AND r.worker LIKE CONCAT('%', #{worker}, '%')


        AND r.result_date >= #{startDate}


        AND r.result_date <= #{endDate}
